export interface AlbumSeedData {
  title: string;
  artistName: string;
  releaseYear: number;
  genres: string[];
  subgenres: string[];
  impactTier: "Landmark" | "Essential" | "Notable";
  impactScore: number;
  summary: string;
  links: { spotify?: string; apple?: string; youtube?: string };
}

function a(title: string, artist: string, year: number, genres: string[], subgenres: string[], tier: "Landmark"|"Essential"|"Notable", score: number, summary: string): AlbumSeedData {
  const q = encodeURIComponent(artist + " " + title);
  return { title, artistName: artist, releaseYear: year, genres, subgenres, impactTier: tier, impactScore: score, summary, links: { spotify: `https://open.spotify.com/search/${q}`, apple: `https://music.apple.com/us/search?term=${q}`, youtube: `https://music.youtube.com/search?q=${q}` } };
}

